impl Solution { pub fn mct_from_leaf_values(black_a: Vec<i32>) -> i32 { let (mut black_stk, mut black_res) = (vec![i32::MAX], 0); for black_x in black_a { while black_stk.last().unwrap() <= &black_x { let black_mid = black_stk.pop().unwrap(); black_res += black_mid * black_stk.last().unwrap().min(&black_x); } black_stk.push(black_x); } while black_stk.len() > 2 { black_res += black_stk.pop().unwrap() * black_stk.last().unwrap(); } black_res } }